package culling

import (
	"os"
	"path/filepath"
	"strings"

	"inference-lab-bench/internal/util"
)

// CullingMeta holds algorithm-specific metadata loaded from a sidecar file
// generated by `bench gen-cull-metadata`. The sidecar format is method-dependent:
// TOML for simple methods (random, noop), binary WAVG for inattention.
type CullingMeta struct {
	Method    string         `toml:"method"`
}

// LoadCullingMeta reads a .cullmeta sidecar file.
// Tries binary formats first (each loader returns nil,nil if format doesn't match),
// then falls back to TOML.
// Returns (nil, nil) if path is empty or the file does not exist.
func LoadCullingMeta(path string) (*CullingMeta, error) {
	if path == "" {
		return nil, nil
	}
	if _, err := os.Stat(path); os.IsNotExist(err) {
		return nil, nil
	}

	// Fall back to TOML
	var meta CullingMeta
	if err := util.LoadTOML(path, &meta); err != nil {
		return nil, err
	}
	return &meta, nil
}

// cullMetaPath returns the sidecar path for a given model and method.
func cullMetaPath(modelPath, method string) string {
	return strings.TrimSuffix(modelPath, filepath.Ext(modelPath)) + "." + method + util.ExtCullMeta
}
